{"title":"Tactical Map — Drones / Sensors / Operators","type":"vega","params":{"spec":"{
  $schema: https://vega.github.io/schema/vega-lite/v5.json,
  description: Sparrow DroneID tactical map: drones\, sensors\, and operators,
  config: {background: "#1a1a2e", view: {stroke: null}},
  layer: [
    {
      data: {
        url: {
          %context%: true,
          %timefield%: @timestamp,
          index: sparrow-droneid-*,
          body: {
            size: 10000,
            _source: ["source.geo.location.lat","source.geo.location.lon","droneid.serial_number","droneid.state","droneid.drone.height_agl","droneid.drone.speed"],
            query: {bool: {must: [{match: {"event.kind": "event"}},{exists: {field: "source.geo.location"}}]}}
          }
        },
        format: {type: "json", property: "hits.hits"}
      },
      transform: [
        {calculate: "datum._source['source.geo.location'] ? datum._source['source.geo.location']['lon'] : null", as: "dlon"},
        {calculate: "datum._source['source.geo.location'] ? datum._source['source.geo.location']['lat'] : null", as: "dlat"},
        {filter: "datum.dlat != null && datum.dlon != null"}
      ],
      mark: {type: "point", shape: "circle", filled: true, size: 80, tooltip: true},
      encoding: {
        longitude: {field: "dlon", type: "quantitative"},
        latitude: {field: "dlat", type: "quantitative"},
        color: {
          field: "_source.droneid.state",
          type: "nominal",
          scale: {domain: ["active","stale","lost"], range: ["#00ff88","#ffaa00","#ff4444"]},
          legend: {title: "Drone State"}
        },
        tooltip: [
          {field: "_source.droneid.serial_number", title: "Serial"},
          {field: "_source.droneid.state", title: "State"},
          {field: "_source.droneid.drone.height_agl", title: "Height AGL (m)"},
          {field: "_source.droneid.drone.speed", title: "Speed (m/s)"}
        ]
      }
    },
    {
      data: {
        url: {
          %context%: true,
          %timefield%: @timestamp,
          index: sparrow-droneid-*,
          body: {
            size: 100,
            _source: ["observer.geo.location.lat","observer.geo.location.lon","observer.name"],
            query: {bool: {must: [{match: {"event.kind": "event"}},{exists: {field: "observer.geo.location"}}]}},
            aggs: {sensors: {terms: {field: "observer.name", size: 50}, aggs: {loc: {top_hits: {size: 1, _source: ["observer.geo.location","observer.name"]}}}}}
          }
        },
        format: {type: "json", property: "aggregations.sensors.buckets"}
      },
      transform: [
        {calculate: "datum.loc.hits.hits[0]._source['observer.geo.location']['lon']", as: "slon"},
        {calculate: "datum.loc.hits.hits[0]._source['observer.geo.location']['lat']", as: "slat"},
        {filter: "datum.slat != null && datum.slon != null"}
      ],
      mark: {type: "point", shape: "square", filled: true, size: 120, color: "#00aaff", tooltip: true},
      encoding: {
        longitude: {field: "slon", type: "quantitative"},
        latitude: {field: "slat", type: "quantitative"},
        tooltip: [{field: "key", title: "Sensor Name"},{field: "doc_count", title: "Detections"}]
      }
    },
    {
      data: {
        url: {
          %context%: true,
          %timefield%: @timestamp,
          index: sparrow-droneid-*,
          body: {
            size: 10000,
            _source: ["droneid.operator.location.lat","droneid.operator.location.lon","droneid.serial_number","droneid.operator.id","droneid.operator.bvlos"],
            query: {bool: {must: [{match: {"event.kind": "event"}},{exists: {field: "droneid.operator.location"}}]}}
          }
        },
        format: {type: "json", property: "hits.hits"}
      },
      transform: [
        {calculate: "datum._source['droneid.operator.location']['lon']", as: "olon"},
        {calculate: "datum._source['droneid.operator.location']['lat']", as: "olat"},
        {filter: "datum.olat != null && datum.olon != null"}
      ],
      mark: {type: "point", shape: "triangle", filled: true, size: 100, color: "#ffcc00", tooltip: true},
      encoding: {
        longitude: {field: "olon", type: "quantitative"},
        latitude: {field: "olat", type: "quantitative"},
        tooltip: [
          {field: "_source.droneid.serial_number", title: "Drone Serial"},
          {field: "_source.droneid.operator.id", title: "Operator ID"},
          {field: "_source.droneid.operator.bvlos", title: "BVLOS"}
        ]
      }
    }
  ]
}"},"aggs":[]}

{"title":"Range vs RSSI Scatter","type":"vega","params":{"spec":"{
  $schema: https://vega.github.io/schema/vega-lite/v5.json,
  description: Range vs RSSI per sensor,
  config: {background: "#1a1a2e", axis: {labelColor: "#ccc", titleColor: "#ccc", gridColor: "#333"}, legend: {labelColor: "#ccc", titleColor: "#ccc"}},
  data: {
    url: {
      %context%: true,
      %timefield%: @timestamp,
      index: sparrow-droneid-*,
      body: {
        size: 0,
        query: {bool: {must: [{match: {"event.kind": "event"}},{exists: {field: "droneid.range.drone_m"}},{exists: {field: "droneid.rf.rssi"}}]}},
        aggs: {
          sensors: {
            terms: {field: "observer.name", size: 30},
            aggs: {
              range_buckets: {
                histogram: {field: "droneid.range.drone_m", interval: 50, min_doc_count: 1},
                aggs: {avg_rssi: {avg: {field: "droneid.rf.rssi"}}}
              }
            }
          }
        }
      }
    },
    format: {type: "json", property: "aggregations.sensors.buckets"}
  },
  transform: [
    {flatten: ["range_buckets.buckets"], as: ["bucket"]},
    {calculate: "datum.bucket.key", as: "range_m"},
    {calculate: "datum.bucket.avg_rssi.value", as: "avg_rssi"},
    {filter: "datum.avg_rssi != null"}
  ],
  mark: {type: "point", filled: true, size: 60, opacity: 0.8},
  encoding: {
    x: {field: "range_m", type: "quantitative", title: "Range (m)", scale: {zero: true}},
    y: {field: "avg_rssi", type: "quantitative", title: "Avg RSSI (dBm)"},
    color: {field: "key", type: "nominal", title: "Sensor"},
    tooltip: [
      {field: "key", title: "Sensor"},
      {field: "range_m", title: "Range (m)"},
      {field: "avg_rssi", title: "Avg RSSI (dBm)", format: ".1f"}
    ]
  }
}"},"aggs":[]}

{"title":"Activity Heatmap — Hour of Day vs Day of Week","type":"vega","params":{"spec":"{
  $schema: https://vega.github.io/schema/vega-lite/v5.json,
  description: Drone activity by day of week and hour of day,
  config: {background: "#1a1a2e", axis: {labelColor: "#ccc", titleColor: "#ccc", gridColor: "#333"}, legend: {labelColor: "#ccc", titleColor: "#ccc"}},
  data: {
    url: {
      %context%: true,
      %timefield%: @timestamp,
      index: sparrow-droneid-*,
      body: {
        size: 0,
        query: {bool: {must: [{match: {"event.kind": "event"}}]}},
        aggs: {
          by_day: {
            terms: {
              script: {source: "doc['@timestamp'].value.dayOfWeekEnum.getDisplayName(TextStyle.SHORT, Locale.ROOT)", lang: "painless"},
              size: 7
            },
            aggs: {
              by_hour: {
                terms: {
                  script: {source: "doc['@timestamp'].value.getHour()", lang: "painless"},
                  size: 24
                },
                aggs: {count: {value_count: {field: "droneid.serial_number"}}}
              }
            }
          }
        }
      }
    },
    format: {type: "json", property: "aggregations.by_day.buckets"}
  },
  transform: [
    {flatten: ["by_hour.buckets"], as: ["hour_bucket"]},
    {calculate: "datum.key", as: "day_of_week"},
    {calculate: "datum.hour_bucket.key", as: "hour"},
    {calculate: "datum.hour_bucket.count.value", as: "detections"}
  ],
  mark: rect,
  encoding: {
    x: {field: "hour", type: "ordinal", title: "Hour of Day", sort: {op: "min", field: "hour"}},
    y: {field: "day_of_week", type: "ordinal", title: "Day of Week", sort: ["Mon","Tue","Wed","Thu","Fri","Sat","Sun"]},
    color: {field: "detections", type: "quantitative", title: "Detections", scale: {scheme: "greenblue"}},
    tooltip: [
      {field: "day_of_week", title: "Day"},
      {field: "hour", title: "Hour"},
      {field: "detections", title: "Detections"}
    ]
  }
}"},"aggs":[]}
